mapper.select:
SELECT message_key
      ,lang_code
      ,message_text
WHERE message_key = #{messageKey}
  AND lang_code = #{langCode}

mapper.update:
UPDATE message_translation
    SET message_text = #{message.message_text}
WHERE message_key = #{message_key}
  AND lang_code = #{message.lang_code}

mapper.delete:
DELETE FROM message_translation
    WHERE message_key = #{message_key}
      AND lang_code = #{message.lang_code}
